import React, {useState, useRef, useEffect} from 'react'
import styled from 'styled-components'
import Checkbox from './Checkbox'
import Search from './static/search.png'
import {useDispatch, useSelector} from 'react-redux'
import {
	openDepartment,
	openCategory,
	openMenswearTop,
	openMenswearBottoms,
	openMenswearOuterwear,
	openMenswearFootwear,
	openMenswearTailoring,
	openMenswearAccessories,
	openWomenswearTop,
	openWomenswearBottoms,
	openWomenswearOuterwear,
	openWomenswearFootwear,
	openWomenswearDresses,
	openWomenswearAccessories,
	openWomenswearBagsAndLugguage,
	openSize,
	openPrice,
	openDesigner,
	openCondition,
	shopSelector
} from '../redux/shopSlice'
//import CheckBoxesWrapper from './CheckBoxesWrapper'
//import SidebarTitles from './SidebarTitles'
import DepartmentWrapper from './DepartmentWrapper'

const SidebarWrapper = styled.div `
display:flex;
flex-direction:column;
align-items:flex-start;
justify-content:center;
width:100%;
`

const SidebarTitles = styled.div `
font-size:1.2rem;
font-weight:700;
`

const SeparationBar = styled.div `
width:100%;
background-color:#BDC0BA;
height:1px;
`

const MenswearTitle = styled.div `
font-wieght:900;
font-size:1rem;
margin-left:-15px;
`

const MenswearSection = styled.div `
display:flex;
flex-direction:column;
margin-left:40px;
`

const WomenswearSection = styled.div `
display:flex;
flex-direction:column;
margin-left:40px;
`

const Catogories = styled.div `
display:flex;
flex-direction:column;
`

const Category = styled.div `
margin:7px 0;
display:flex;
justify-content:space-between;
width:100%;
`

const Name = styled.div `
font-size:0.8rem;
font-weight:500;
`

const Arrow = styled.div `
width:10px;
height:10px;
background-color:#1C1C1C;
-webkit-clip-path:polygon(0 40%, 50% 85%, 100% 40%, 100% 55%, 50% 100%, 0 55%);
`

const DesignerSearchbarWrapper = styled.div `
position:relative;
margin:20px 0;
display:flex;
align-items:center;
margin-left:20px;
`

const DesignerSearchBar = styled.input `
width:80%;
height:30px;
border-radius:6px;
border:1px solid grey;
`

const SearchImage = styled.div `
background-image:url(${Search });
width:15px;
height:15px;
background-position:center;
background-size:cover;
position:absolute;
margin-left:10px;
background-color:white;
`

const PriceSection = styled.div `
display:flex;
justify-content:center;
align-items:center;
margin:20px 0;
`

const MinPrice = styled.input `
margin-right:10px;
width:70px;
height:25px;
border-radius:4px;
border:1px solid grey;
`

const MaxPrice = styled.input `
margin-left:10px;
width:70px;
height:25px;
border-radius:4px;
border:1px solid grey;
`

const open = {
	'display':'flex'
}

const CheckBoxesWrapper = styled.div `
display:flex;
flex-direction:column;
margin-left:20px;
`

export default function Sidebar () {
	const dispatch = useDispatch()
	const sidebarSelect = useSelector(shopSelector)
	const [designers, setDesigners] = useState([])
	const [sizes, setSizes] = useState([])
	const [departments, setDepartments] = useState([])
	const [conditions, setConditions] = useState([])
	const [categories, setCategories] = useState([])
	const [subCategories, setSubCategories] = useState([])

	useEffect(() => {
		async function fetchDesigners () {
			const result = await fetch('http://localhost:5001/designers')
			const data = await result.json()
			setDesigners(() => {
				let newDesigners = []
				data.forEach(designer => newDesigners.push(designer))
				return newDesigners
			})
		}
		async function fetchSizes () {
			const result = await fetch('http://localhost:5001/size')
			const data = await result.json()
			setSizes(() => {
				let newSizes = []
				data.forEach(size => newSizes.push(size))
				return newSizes
			})
		}
		async function fetchDepartments () {
			const result = await fetch('http://localhost:5001/departments')
			const data = await result.json()
			setDepartments(() => {
				let newDepartments = []
				data.forEach(department => newDepartments.push(department))
				return newDepartments
			})
		}
		async function fetchConditions () {
			const result = await fetch('http://localhost:5001/condition')
			const data = await result.json()
			setConditions(() => {
				let newCondition = []
				data.forEach(condition => newCondition.push(condition))
				return newCondition
			})
		}
		async function fetchCategories () {
			const result = await fetch('http://localhost:5001/categories')
			const data = await result.json()
			setCategories(() => {
				let newCategories = []
				data.forEach(category => newCategories.push(category))
				return newCategories
			})
		}
		async function fetchSubCategories () {
			const result = await fetch('http://localhost:5001/subCategories')
			const data = await result.json()
			setSubCategories(() => {
				let newSubCategories = []
				data.forEach(subcategory => newSubCategories.push(subcategory))
				return newSubCategories
			})
		}
		fetchDesigners ()
		fetchSizes ()
		fetchDepartments ()
		fetchConditions ()
		fetchCategories ()
		fetchSubCategories ()
	},[])

	const handleDepartmentClick = () => {
		dispatch(openDepartment())
	}

	const handleMTopClick = () => {
		dispatch(openMenswearTop())
	}

	const handleMBottomsClick = () => {
		dispatch(openMenswearBottoms())
	}

	const handleMOuterwearClick = () => {
		dispatch(openMenswearOuterwear())
	}

	const handleMFootwearClick = () => {
		dispatch(openMenswearFootwear())
	}

	const handleMTailoringClick = () => {
		dispatch(openMenswearTailoring())
	}

	const handleMAccessoriesClick = () => {
		dispatch(openMenswearAccessories())
	}

	const handleWTopClick = () => {
		dispatch(openWomenswearTop())
	}

	const handleWBottomsClick = () => {
		dispatch(openWomenswearBottoms())
	}

	const handleWOuterwearClick = () => {
		dispatch(openWomenswearOuterwear())
	}

	const handleWFootwearClick = () => {
		dispatch(openWomenswearFootwear())
	}

	const handleWDressesClick = () => {
		dispatch(openWomenswearDresses())
	}

	const handleWAccessoriesClick = () => {
		dispatch(openWomenswearAccessories())
	}

	const handleWBagsClick = () => {
		dispatch(openWomenswearBagsAndLugguage())
	}

	const handlePriceClick = () => {
		dispatch(openPrice())
	}

	const handleSizeClick = () => {
		dispatch(openSize())
	}


	const handleDesignerClick = () => {
		dispatch(openDesigner())
	}

	const handleConditionClick = () => {
		dispatch(openCondition())
	}

	const handleCategoryClick = () => {
		dispatch(openCategory())
	}

	return (
		<SidebarWrapper>
			<DepartmentWrapper>
				<SidebarTitles onClick={handleDepartmentClick}>Department</SidebarTitles>
				{ sidebarSelect.sidebar.department ? 
				<CheckBoxesWrapper>
					{departments.map(department => <Checkbox key={department.id} value={department}></Checkbox>)}
				</CheckBoxesWrapper> : null}
			</DepartmentWrapper>
			<SeparationBar/>
			<DepartmentWrapper>
				<SidebarTitles onClick={handleCategoryClick}>Category</SidebarTitles>
				{ sidebarSelect.sidebar.category ?
				<>
				<MenswearSection>
					<MenswearTitle>Menswear</MenswearTitle>
					{categories.filter(category => category.department_id === 1).map(category => 
					<Catogories key={category.id}>
						<Category onClick={handleMTopClick}>
							<Name>{category.name}</Name>
							<Arrow></Arrow>
						</Category>
						{ sidebarSelect.sidebar.menswear.top ?
						<CheckBoxesWrapper>
							{console.log(subCategories.filter(subCategory => subCategory.category_id == category.id)).map(subCategory =>
								console.log(subCategory)
								)}
							{subCategories.filter(subCategory => subCategory.category_id === category.id).map(subCategory =>
								<Checkbox value={subCategory}></Checkbox>
								)}
						</CheckBoxesWrapper>:null}
					</Catogories>
					)}
				</MenswearSection>
				<WomenswearSection>
					<MenswearTitle>Womenswear</MenswearTitle>
						<Catogories>
							<Category onClick={handleWTopClick}>
								<Name>Top</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.top ? 
							<CheckBoxesWrapper>
								<Checkbox value='AllTops'>All Tops</Checkbox>
								<Checkbox value='CropTops'>Crop Tops</Checkbox>
								<Checkbox value='Bodysuits'>Bodysuits</Checkbox>
								<Checkbox value='LongSleeveT-shirts'>Long Sleeve T-shirts</Checkbox>
								<Checkbox value='Shirts'>Shirts</Checkbox>
								<Checkbox value='Sweaters'>Sweaters</Checkbox>
								<Checkbox value='SweatshirtsAndHoodies'>Sweatshirts & Hoodies</Checkbox>
								<Checkbox value='TankTopAndSleeveless'>TankTop & Sleeveless</Checkbox>
								<Checkbox value='Jerseys'>Jerseys</Checkbox>
							</CheckBoxesWrapper>:null}
						</Catogories>
						<Catogories>
							<Category onClick={handleWBottomsClick}>
								<Name>Bottoms</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.bottoms ? 
							<CheckBoxesWrapper>
								<Checkbox value='AllBottoms'>All Bottoms</Checkbox>
								<Checkbox value='CasualPants'>Casual Pants</Checkbox>
								<Checkbox value='Joggers'>Joggers</Checkbox>
								<Checkbox value='Jeans'>Jeans</Checkbox>
								<Checkbox value='Leggings'>Leggings</Checkbox>
								<Checkbox value='Jumpsuits'>Jumpsuits</Checkbox>
								<Checkbox value='Shorts'>Shorts</Checkbox>
								<Checkbox value='SweatpantsAndJoggers'>Sweatpants & Joggers</Checkbox>
								<Checkbox value='MaxiSkirts'>Maxi Skirts</Checkbox>
								<Checkbox value='MidiSkirts'>Midi Skirts</Checkbox>
								<Checkbox value='MiniSkirts'>Mini Skirts</Checkbox>
							</CheckBoxesWrapper>:null}
						</Catogories>
						<Catogories>
							<Category onClick={handleWOuterwearClick}>
								<Name>OuterWear</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.outerwear ? 
							<CheckBoxesWrapper>
							<Checkbox value='AllOuterwear'>All Outerwear</Checkbox>
							<Checkbox value='Blazers'>Blazer</Checkbox>
							<Checkbox value='DenimJackets'>Denim Jackets</Checkbox>
							<Checkbox value='Coats'>Coats</Checkbox>
							<Checkbox value='Jackets'>Jackets</Checkbox>
							<Checkbox value='Vests'>Vests</Checkbox>
						</CheckBoxesWrapper>:null}
						</Catogories>
						<Catogories>
							<Category onClick={handleWFootwearClick}>
								<Name>Footwear</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.footwear ? 
							<CheckBoxesWrapper>
								<Checkbox value='AllFootwear'>All Footwear</Checkbox>
								<Checkbox value='Boots'>Boots</Checkbox>
								<Checkbox value='Heels'>Heels</Checkbox>
								<Checkbox value='Low-TopSneakers'>Low-Top Sneakers</Checkbox>
								<Checkbox value='Sandals'>Sandals</Checkbox>
								<Checkbox value='Flats'>Flats</Checkbox>
							</CheckBoxesWrapper>:null}
						</Catogories>
						<Catogories>
							<Category onClick={handleWDressesClick}>
								<Name>Dresses</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.dresses ? 
							<CheckBoxesWrapper>
								<Checkbox value='AllDresses'>All Dresses</Checkbox>
								<Checkbox value='MaxiDresses'>Maxi Dresses</Checkbox>
								<Checkbox value='MidiDresses'>Midi Dresses</Checkbox>
								<Checkbox value='MiniDresses'>Mini Dresses</Checkbox>
							</CheckBoxesWrapper>:null}
						</Catogories>
						<Catogories>
							<Category onClick={handleWAccessoriesClick}>
								<Name>Accessories</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.accessories ? 
							<CheckBoxesWrapper>
								<Checkbox value='AllAccessories'>All Accessories</Checkbox>
								<Checkbox value='Belts'>Belts</Checkbox>
								<Checkbox value='Glasses'>Glasses</Checkbox>
								<Checkbox value='GlovesAndScarves'>Gloves & Scarves</Checkbox>
								<Checkbox value='Hats'>Hats</Checkbox>
								<Checkbox value='JewelryAndWatches'>Jewelry & Watches</Checkbox>
								<Checkbox value='Wallets'>Wallets</Checkbox>
								<Checkbox value='Sunglasses'>Sunglasses</Checkbox>
								<Checkbox value='Scarves'>Scarves</Checkbox>
							</CheckBoxesWrapper>:null}
						</Catogories>
						<Catogories>
							<Category onClick={handleWBagsClick}>
								<Name>Bags & Lugguage</Name>
								<Arrow></Arrow>
							</Category>
							{ sidebarSelect.sidebar.womenswear.bagsAndLugguage ? 
							<CheckBoxesWrapper>
								<Checkbox value='AllBagsAndLugguage'>All Bags & Lugguage</Checkbox>
								<Checkbox value='CrossbodyBags'>Crossbody Bags</Checkbox>
								<Checkbox value='HandleBags'>Handle Bags</Checkbox>
								<Checkbox value='ShoulderBags'>Shoulder Bags</Checkbox>
								<Checkbox value='ToteBags'>Tote Bags</Checkbox>
							</CheckBoxesWrapper>:null}
						</Catogories>
				</WomenswearSection></>:null}
			</DepartmentWrapper>
			<SeparationBar/>
			<DepartmentWrapper>
				<SidebarTitles onClick={handleSizeClick}>Size</SidebarTitles>
				{ sidebarSelect.sidebar.size ? 
				<CheckBoxesWrapper>
					{sizes.map(size => <Checkbox key={size.id} value={size}></Checkbox>)}
				</CheckBoxesWrapper>:null}
			</DepartmentWrapper>
			<SeparationBar/>
			<DepartmentWrapper>
				<SidebarTitles onClick={handleDesignerClick}>Designer</SidebarTitles>
				{ sidebarSelect.sidebar.designer ? 
				<>
				<DesignerSearchbarWrapper>
					<SearchImage/>
					<DesignerSearchBar></DesignerSearchBar>
				</DesignerSearchbarWrapper>
				<CheckBoxesWrapper>
					{designers.map(designer => <Checkbox key={designer.id} value={designer}></Checkbox>)}
				</CheckBoxesWrapper></>:null}
			</DepartmentWrapper>
			<SeparationBar/>
			<DepartmentWrapper>
				<SidebarTitles onClick={handlePriceClick}>Price</SidebarTitles>
				{ sidebarSelect.sidebar.price ? 
				<PriceSection>
					<MinPrice></MinPrice>
					<div>to</div>
					<MaxPrice></MaxPrice>
				</PriceSection>:null}
			</DepartmentWrapper>
			<SeparationBar/>
			<DepartmentWrapper>
				<SidebarTitles onClick={handleConditionClick}>Condition</SidebarTitles>
				{ sidebarSelect.sidebar.condition ? 
				<CheckBoxesWrapper>
					{conditions.map(condition => <Checkbox key = {condition.id} value={condition}></Checkbox>)}
				</CheckBoxesWrapper>:null}
			</DepartmentWrapper>
			<SeparationBar/>
		</SidebarWrapper>
	)
}
